      END_STATE();
    case 66:
      ACCEPT_TOKEN(anon_sym_right);
      END_STATE();
    case 67:
      ACCEPT_TOKEN(sym_where);
      END_STATE();
    case 68:
      ACCEPT_TOKEN(sym_effect);
      END_STATE();
    case 69:
