      END_STATE();
    case 71:
      ACCEPT_TOKEN(sym_module);
      END_STATE();
    case 72:
      if (lookahead == 'g') ADVANCE(73);
      END_STATE();
    case 73:
      ACCEPT_TOKEN(sym_exposing);
      END_STATE();
    default:
      return false;
